#include <stdbool.h>

int main(){printf("--- Enteros ---\n");int edad=15;int año=2026;int cantidad=2;printf("Tienes %d años\n",edad);printf("Estamos en el año %d\n", año);printf("Tu has ordenado %d items\n",cantidad);printf("--- Floats ---\n");float nota=7.2;float precio=19.99;float temperatura=-1.3;printf("Tu nota de matematicas es %.1f\n",nota);printf("El precio del item es de $%.2f\n",precio);printf("La temperatura es de %.1f grados centigrados\n",temperatura);printf("--- Doubles ---\n");double pi=3.14159265265358979;double e=2.7182818284590;printf("Los primeros 14 digitos de pi es: %.14lf\n",pi);printf("Los primeros 12 digitos del numero de euler es: %.12lf\n",e);printf("--- Caracteres ---\n");char grado='A';char simbolo='!';char moneda='$';printf("Tu nota del examen de matematicas es de %c\n",grado);printf("Tu simbolo favorito (o tal vez no) es %c\n",simbolo);printf("La moneda que se va a utilizar es %c\n",moneda);printf("--- Strings (caracteres) ---\n");char nombre[]="Alessandro";char comida[]="papas fritas";char email[]="tuputasexy666@example.com";printf("Hola %s!\n",nombre);printf("Tu comida favorita es %s\n",comida);printf("Tu correo electronico es %s\n",email);printf("--- Bools ---\n");bool enLinea=1;bool estudiante=1;bool enVenta=0;printf("%d\n",enLinea);if(enLinea){printf("Estas en linea\n");}else{printf("Estas offline\n");}if(estudiante){printf("Eres un estudiante\n");}else{printf("No eres un estudiante\n");}if(enVenta){printf("Este producto esta a la venta\n");}else{printf("Este producto no esta a la venta\n");}return 0;}
